8,"\u8be5\u7b97\u5b50\u6839\u636e\u5b57\u6bcd\u6570\u5b57\u5b57\u7b26\u6216":314,"\u8be5\u7b97\u5b50\u6839\u636e\u6240\u542b\u89c6\u9891\u7684\u5206\u8fa8\u7387\u6765\u8fc7\u6ee4\u6570\u636e\u6837\u672c":365,"\u8be5\u7b97\u5b50\u6839\u636e\u6307\u5b9a\u5b57\u6bb5\u7684\u503c\u4ece\u6570\u636e\u96c6\u4e2d\u9009\u62e9\u9876\u90e8\u6837\u672c":478,"\u8be5\u7b97\u5b50\u6839\u636e\u6307\u5b9a\u5b57\u6bb5\u7684\u503c\u9891\u7387\u9009\u62e9\u6837\u672c":473,"\u8be5\u7b97\u5b50\u6839\u636e\u6307\u5b9a\u7684\u6a21\u5f0f\u8f6c\u6362\u4e2d\u6587\u6587\u672c":387,"\u8be5\u7b97\u5b50\u6839\u636e\u6307\u5b9a\u7684\u6bd4\u4f8b\u6216\u56fa\u5b9a\u6570\u91cf\u968f\u673a\u9009\u62e9\u4e00\u90e8\u5206\u6837\u672c":475,"\u8be5\u7b97\u5b50\u6839\u636e\u63d0\u4f9b\u7684\u56fe\u50cf\u548c\u6307\u5b9a\u7684\u53c2\u6570\u751f\u6210\u6587\u672c":414,"\u8be5\u7b97\u5b50\u6839\u636e\u63d0\u4f9b\u7684\u6700\u5c0f\u548c\u6700\u5927ifd\u5206\u6570\u9608\u503c\u6765\u51b3\u5b9a\u4fdd\u7559\u6216\u8fc7\u6ee4\u6837\u672c":336,"\u8be5\u7b97\u5b50\u6839\u636e\u6587\u672c\u4e2d\u7279\u6b8a\u5b57\u7b26\u7684\u6bd4\u4f8b\u6765\u8fc7\u6ee4\u6837\u672c":346,"\u8be5\u7b97\u5b50\u6839\u636e\u6700\u5927\u9762\u90e8\u533a\u57df\u4e0e\u603b\u56fe\u50cf\u9762\u79ef\u7684\u6bd4\u7387\u6765\u8fc7\u6ee4\u6837\u672c":325,"\u8be5\u7b97\u5b50\u6839\u636e\u6807\u8bb0\u8bcd\u7684\u6bd4\u4f8b\u7b5b\u9009\u6837\u672c":320,"\u8be5\u7b97\u5b50\u6839\u636e\u6837\u672c\u4e2d\u6700\u957f\u884c\u7684\u957f\u5ea6\u6765\u8fc7\u6ee4\u6837\u672c":343,"\u8be5\u7b97\u5b50\u6839\u636e\u6837\u672c\u7684\u5e73\u5747\u884c\u957f\u5ea6\u8fdb\u884c\u8fc7\u6ee4":318,"\u8be5\u7b97\u5b50\u6839\u636e\u6837\u672c\u7684\u603b\u6587\u672c\u957f\u5ea6\u8fc7\u6ee4\u6837\u672c":354,"\u8be5\u7b97\u5b50\u6839\u636e\u68c0\u6d4b\u5230\u7684\u6587\u672c\u533a\u57df\u4e0e\u603b\u5e27\u9762\u79ef\u7684\u6bd4\u4f8b\u6765\u8fc7\u6ee4\u6570\u636e":364,"\u8be5\u7b97\u5b50\u6839\u636e\u7ed9\u5b9a\u952e\u7684\u503c\u5bf9\u6837\u672c\u8fdb\u884c\u5206\u7ec4":379